			if (data.mediaType) sessionStorage.setItem(SS_KEY_MEDIA_TYPE, data.mediaType);
			else sessionStorage.removeItem(SS_KEY_MEDIA_TYPE);
		} catch {
			// sessionStorage may be unavailable (private mode, SSR); ignore.
		}
	});

